mapper.select:
SELECT s.id, s.week_no, s.unit_id, s.user_id, su.unit_name, u.username, u.real_name, s.attendance_days, s.attendance_score, s.weekly_work_status, s.weekly_work_score, s.discipline_score, s.discipline_remark, s.total_score, s.level, s.status, s.calculate_time FROM work_score s INNER JOIN sys_user u ON u.id = s.user_id LEFT JOIN sys_org_unit su ON su.id = s.unit_id WHERE u.is_deleted = FALSE
AND s.week_no = #{request.weekNo}
AND su.unit_name LIKE CONCAT('%', #{request.unitName}, '%')
AND s.status = #{request.status}
AND s.unit_id = #{request.unitId}
ORDER BY
s.total_score DESC, s.level ASC,
s.level ASC,
s.calculate_time DESC, s.id DESC

SELECT u.unit_id, u.id AS user_id, COUNT(DISTINCT a.attendance_date) AS attendance_days, MAX(w.status) AS weekly_work_status FROM sys_user u LEFT JOIN attendance_record a ON a.user_id = u.id AND a.valid_flag = 1 AND a.attendance_date >= #{weekStart} AND a.attendance_date <= #{weekEnd} LEFT JOIN weekly_work w ON w.user_id = u.id AND w.week_no = #{weekNo} WHERE u.is_deleted = FALSE
AND u.unit_id = #{unitId}
GROUP BY u.unit_id, u.id ORDER BY u.unit_id, u.id
